            if (mpCurrMsg->mSelectNum == 0) {
                *pMsgNo = 0x1BC9;
            } else {
                *pMsgNo = 0x1BCC;
            }
            break;

        case 0x1BCC:
            *pMsgNo = 0x1BCA;
